public class CustomModel<T extends Entity> extends EntityModel<T> {
	// This layer location should be baked with EntityRendererProvider.Context in the entity renderer and passed into this model's constructor
	public static final ModelLayerLocation LAYER_LOCATION = new ModelLayerLocation(new ResourceLocation("modid", "custommodel"), "main");
	private final ModelPart deep_guardian;

	public CustomModel(ModelPart root) {
		this.deep_guardian = root.getChild("deep_guardian");
	}

	public static LayerDefinition createBodyLayer() {
		MeshDefinition meshdefinition = new MeshDefinition();
		PartDefinition partdefinition = meshdefinition.getRoot();

		PartDefinition deep_guardian = partdefinition.addOrReplaceChild("deep_guardian", CubeListBuilder.create().texOffs(0, 0).addBox(-8.0F, -16.0F, -6.0F, 16.0F, 16.0F, 12.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-6.0F, 0.0F, -5.0F, 12.0F, 16.0F, 10.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-5.0F, 16.0F, -4.0F, 10.0F, 12.0F, 8.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-4.0F, 28.0F, -3.0F, 8.0F, 10.0F, 6.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-24.0F, 38.0F, -2.0F, 48.0F, 6.0F, 4.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-6.0F, -28.0F, -5.0F, 12.0F, 12.0F, 10.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-7.0F, -32.0F, -6.0F, 14.0F, 8.0F, 12.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(8.0F, -14.0F, -3.0F, 6.0F, 10.0F, 6.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-14.0F, -14.0F, -3.0F, 6.0F, 10.0F, 6.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-12.0F, -20.0F, -1.0F, 2.0F, 24.0F, 2.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(8.0F, -8.0F, 6.0F, 2.0F, 4.0F, 2.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(-10.0F, -10.0F, 6.0F, 2.0F, 4.0F, 2.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(2.0F, -34.0F, 6.0F, 2.0F, 4.0F, 2.0F, new CubeDeformation(0.0F))
		.texOffs(0, 0).addBox(4.0F, 16.0F, 5.0F, 2.0F, 4.0F, 2.0F, new CubeDeformation(0.0F)), PartPose.offset(0.0F, 24.0F, 0.0F));

		return LayerDefinition.create(meshdefinition, 16, 16);
	}

	@Override
	public void setupAnim(Entity entity, float limbSwing, float limbSwingAmount, float ageInTicks, float netHeadYaw, float headPitch) {

	}

	@Override
	public void renderToBuffer(PoseStack poseStack, VertexConsumer vertexConsumer, int packedLight, int packedOverlay, float red, float green, float blue, float alpha) {
		deep_guardian.render(poseStack, vertexConsumer, packedLight, packedOverlay, red, green, blue, alpha);
	}
}
